import React, { useState, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Editor } from './components/Editor';
import { ImageGallery } from './components/ImageGallery';

const App: React.FC = () => {
  const [story, setStory] = useState<string>('');
  const [modifiedStory, setModifiedStory] = useState<string>('');
  const [imageConcept, setImageConcept] = useState<string>('');
  const [imageConceptEnglish, setImageConceptEnglish] = useState<string>('');
  const [images, setImages] = useState<string[]>([]);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleCopyStory = useCallback(() => {
    if (!story) return;
    navigator.clipboard.writeText(story).then(() => {
      alert('Original story copied!');
    }).catch(err => console.error('Failed to copy: ', err));
  }, [story]);

  const handleClearStory = useCallback(() => setStory(''), []);

  const handleCopyModified = useCallback(() => {
    if (!modifiedStory) return;
    navigator.clipboard.writeText(modifiedStory).then(() => {
      alert('Modified story copied!');
    }).catch(err => console.error('Failed to copy: ', err));
  }, [modifiedStory]);

  const handleClearModified = useCallback(() => setModifiedStory(''), []);

  const handleCopyConcept = useCallback(() => {
    if (!imageConcept) return;
    navigator.clipboard.writeText(imageConcept).then(() => {
      alert('Image concept (Thai) copied!');
    }).catch(err => console.error('Failed to copy: ', err));
  }, [imageConcept]);

  const handleClearConcept = useCallback(() => setImageConcept(''), []);

  const handleCopyConceptEnglish = useCallback(() => {
    if (!imageConceptEnglish) return;
    navigator.clipboard.writeText(imageConceptEnglish).then(() => {
      alert('Image concept (English) copied!');
    }).catch(err => console.error('Failed to copy: ', err));
  }, [imageConceptEnglish]);

  const handleClearConceptEnglish = useCallback(() => setImageConceptEnglish(''), []);

  const handleGenerate = async () => {
    // Priority order for prompt source: English Concept > Thai Concept > Modified Story > Original Story
    const promptSource = 
      imageConceptEnglish.trim() || 
      imageConcept.trim() || 
      modifiedStory.trim() || 
      story.trim();

    if (!promptSource) {
      setError("Please enter a story or concept in any field first.");
      return;
    }

    setIsGenerating(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            {
              text: `Generate a high-quality, cinematic image based on this description: ${promptSource}`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: "16:9"
          }
        },
      });

      const newImages: string[] = [];
      if (response.candidates && response.candidates[0].content.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            const imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            newImages.push(imageUrl);
          }
        }
      }

      if (newImages.length > 0) {
        setImages(prev => [newImages[0], ...prev]);
      } else {
        setError("No image was generated. Please try a different story.");
      }
    } catch (err: any) {
      console.error("Image generation failed:", err);
      setError(err.message || "Failed to generate image. Please try again later.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center p-4 md:p-8">
      <div className="w-full max-w-4xl space-y-8">
        {/* Header Section */}
        <header className="text-center space-y-2">
          <h1 className="text-4xl font-bold text-slate-800 tracking-tight">
            Story Image Generator
          </h1>
          <p className="text-slate-500">Transform your words into visual art</p>
        </header>

        {/* Primary Story Editor */}
        <section>
          <Editor 
            label="Story"
            placeholder="Write your original story here..."
            value={story} 
            onChange={setStory} 
            onCopy={handleCopyStory} 
            onClear={handleClearStory}
          />
        </section>

        {/* Modified Story Editor */}
        <section>
          <Editor 
            label="Modified Story"
            placeholder="The refined or translated version will appear here..."
            value={modifiedStory} 
            onChange={setModifiedStory} 
            onCopy={handleCopyModified} 
            onClear={handleClearModified}
          />
        </section>

        {/* Image Concept in Thai Editor */}
        <section>
          <Editor 
            label="Image Concept in Thai"
            placeholder="Enter the visual description in Thai here..."
            value={imageConcept} 
            onChange={setImageConcept} 
            onCopy={handleCopyConcept} 
            onClear={handleClearConcept}
          />
        </section>

        {/* Image Concept in English Editor */}
        <section>
          <Editor 
            label="Image Concept in English"
            placeholder="Enter the visual description in English here..."
            value={imageConceptEnglish} 
            onChange={setImageConceptEnglish} 
            onCopy={handleCopyConceptEnglish} 
            onClear={handleClearConceptEnglish}
          />
        </section>

        {/* Action Button Section */}
        <section className="flex justify-center">
          <button
            onClick={handleGenerate}
            disabled={isGenerating || (!story.trim() && !modifiedStory.trim() && !imageConcept.trim() && !imageConceptEnglish.trim())}
            className={`
              px-10 py-4 rounded-xl font-semibold text-lg transition-all transform active:scale-95
              flex items-center space-x-3 shadow-lg w-full md:w-auto
              ${isGenerating 
                ? 'bg-slate-300 cursor-not-allowed text-slate-500' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white hover:shadow-indigo-200'
              }
            `}
          >
            {isGenerating ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <span>Generating Image...</span>
              </>
            ) : (
              <>
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                <span>Create Image</span>
              </>
            )}
          </button>
        </section>

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded shadow-sm text-red-700">
            {error}
          </div>
        )}

        {/* Output Gallery */}
        <section>
           <ImageGallery images={images} />
        </section>

        {/* Footer info */}
        <footer className="py-12 text-center text-slate-400 text-sm">
          <p>© 2024 Story Image Generator • Powered by Gemini AI</p>
        </footer>
      </div>
    </div>
  );
};

